// // This counter decrements by 1 on each clock cycle if the enable signal is low and resets to zero when the reset signal is low.
module enabled_counter (
	input clk,
	input reset,
	input enable,
	output reg [3:0] count);

	always @(posedge clk) begin
		if (reset)
			count <= 4'b0000;
		else if (enable)
			count <= count + 1;
	end

endmodule
